INSERT INTO `email_outbox` VALUES (1,'user_welcome_account','playinggamer03@gmail.com','aa','Tai khoan cua ban da san sang','<!doctype html>\n<html lang=\"vi\">\n<head>\n    <meta charset=\"utf-8\">\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n    <title>Tài khoản đã được tạo</title>\n</head>\n<body style=\"margin:0;background:#f8fafc;font-family:Arial,Helvetica,sans-serif;color:#0f172a;\">\n    <table role=\"presentation\" width=\"100%\" cellspacing=\"0\" cellpadding=\"0\" style=\"background:#f8fafc;padding:24px 12px;\">\n        <tr>\n            <td align=\"center\">\n                <table role=\"presentation\" width=\"100%\" cellspacing=\"0\" cellpadding=\"0\" style=\"max-width:680px;background:#ffffff;border-radius:20px;overflow:hidden;border:1px solid #e2e8f0;\">\n                    <tr>\n                        <td style=\"background:linear-gradient(135deg,#0f172a 0%,#1d4ed8 100%);padding:28px 32px;\">\n                            <div style=\"font-size:12px;letter-spacing:0.16em;text-transform:uppercase;color:#bfdbfe;font-weight:700;\">English Center Platform</div>\n                            <div style=\"margin-top:10px;font-size:28px;line-height:1.2;font-weight:800;color:#ffffff;\">Tài khoản đã được tạo</div>\n                            <div style=\"margin-top:12px;font-size:15px;line-height:1.7;color:#dbeafe;\">Xin chào <strong>aa</strong>, hệ thống vừa tạo tài khoản học viên cho bạn.</div>\n                        </td>\n                    </tr>\n                    <tr>\n                        <td style=\"padding:28px 32px;\">\n                            <p style=\"margin:0 0 16px;font-size:15px;line-height:1.8;color:#334155;\">Bạn có thể đăng nhập bằng thông tin sau:</p>\n        <div style=\"margin:0 0 20px;padding:18px 20px;border-radius:18px;background:#f8fafc;border:1px solid #e2e8f0;\">\n            <div style=\"margin-bottom:8px;\"><strong>Tên đăng nhập:</strong> aaa</div>\n            <div><strong>Mật khẩu tạm:</strong> 123456789</div>\n        </div>\n        <p style=\"margin:0 0 16px;\"><a href=\"http://localhost:8080/?page=login\" style=\"display:inline-block;padding:12px 18px;border-radius:999px;background:#1d4ed8;color:#ffffff;text-decoration:none;font-weight:700;\">Đăng nhập ngay</a></p>\n        <p style=\"margin:0;font-size:14px;line-height:1.7;color:#64748b;\">Vì lý do bảo mật, bạn nên đổi mật khẩu ngay sau lần đăng nhập đầu tiên.</p>\n                        </td>\n                    </tr>\n                    <tr>\n                        <td style=\"padding:18px 32px;background:#f8fafc;border-top:1px solid #e2e8f0;font-size:12px;line-height:1.8;color:#64748b;\">\n                            Email được gửi tự động từ hệ thống. Nếu bạn cần hỗ trợ, vui lòng phản hồi email này hoặc liên hệ trung tâm.\n                        </td>\n                    </tr>\n                </table>\n            </td>\n        </tr>\n    </table>\n</body>\n</html>','Tai khoan cua ban da duoc tao.\nTen dang nhap: aaa\nMat khau tam: 123456789\nDang nhap tai: http://localhost:8080/?page=login\nBan nen doi mat khau sau khi dang nhap lan dau.','{\"username\": \"aaa\", \"full_name\": \"aa\", \"login_url\": \"http://localhost:8080/?page=login\", \"role_label\": \"học viên\", \"plain_password\": \"123456789\"}','{\"X-App-Template\": \"user_welcome_account\"}','{\"type\": \"welcome_account\", \"user_id\": 214}','pending',0,NULL,NULL,NULL,'2026-05-11 17:57:01',NULL,NULL,'2026-05-11 17:57:01','2026-05-11 17:57:01');
